using System.Text;

namespace Qmd.Core.Skills;

internal record EmbeddedSkillFile(string RelativePath, string Content);

internal static class EmbeddedSkills
{
    private const string SkillMdBase64 = "";

    private const string McpSetupBase64 = "";

    private static readonly Dictionary<string, string> EmbeddedFiles = new()
    {
        ["SKILL.md"] = SkillMdBase64,
        ["references/mcp-setup.md"] = McpSetupBase64,
    };

    public static List<EmbeddedSkillFile> GetEmbeddedQmdSkillFiles()
    {
        return EmbeddedFiles
            .Select(kvp => new EmbeddedSkillFile(
                kvp.Key,
                Encoding.UTF8.GetString(Convert.FromBase64String(kvp.Value))))
            .ToList();
    }

    public static string GetEmbeddedQmdSkillContent()
    {
        return Encoding.UTF8.GetString(Convert.FromBase64String(EmbeddedFiles["SKILL.md"]));
    }
}
